183	      const cov = await this.coverage(subjectId, ktpTopicId);
184	      // Цели: KC с дефицитом активных, либо одна цель на узел (если KC нет).
185	      const targets: Array<{ kcId?: string; title: string; deficit: number }> = kcs.length
186	        ? cov.perKc
